  1	import * as React from 'react';
  2	import {
  3	  Checkbox,
  4	  Divider,
  5	  Dropdown,
  6	  DropdownList,
  7	  MenuToggle,
  8	  MenuToggleElement,
  9	  Radio,
 10	  Tooltip,
 11	  TooltipPosition
 12	} from '@patternfly/react-core';
 13	import { kialiStyle } from 'styles/StyleUtils';
 14	import isEqual from 'lodash/isEqual';
 15	import { location, router, URLParam } from '../../app/History';
 16	import { MetricsSettings, Quantiles, allQuantiles, LabelsSettings } from './MetricsSettings';
 17	import {
 18	  mergeLabelFilter,
 19	  prettyLabelValues,
 20	  combineLabelsSettings,
 21	  retrieveMetricsSettings
 22	} from 'components/Metrics/Helper';
 23	import { itemStyleWithoutInfo, titleStyle } from 'styles/DropdownStyles';
 24	import { PromLabel } from 'types/Metrics';
 25	import { KialiIcon } from 'config/KialiIcon';
 26	import { classes } from 'typestyle';
 27	
 28	interface Props {
 29	  direction: string;
 30	  hasHistograms: boolean;
 31	  hasHistogramsAverage: boolean;
 32	  hasHistogramsPercentiles: boolean;
 33	  labelsSettings: LabelsSettings;
 34	  onChanged: (state: MetricsSettings) => void;
 35	  onLabelsFiltersChanged: (labelsFilters: LabelsSettings) => void;
 36	}
 37	
 38	type State = MetricsSettings & {
 39	  allSelected: boolean;
 40	  isOpen: boolean;
 41	};
 42	
 43	const checkboxSelectAllStyle = kialiStyle({ marginLeft: '0.5rem' });
 44	const secondLevelStyle = kialiStyle({ marginLeft: '1rem' });
 45	const spacerStyle = kialiStyle({ height: '0.5rem' });
 46	const titleLabelStyle = kialiStyle({ marginBottom: '0.5rem', fontSize: 'small' });
 47	const labelStyle = kialiStyle({ display: 'inline-block' });
 48	const checkboxStyle = kialiStyle({ marginLeft: '1rem' });
 49	
 50	export class MetricsSettingsDropdown extends React.Component<Props, State> {
 51	  constructor(props: Props) {
 52	    super(props);
 53	    const settings = retrieveMetricsSettings();
 54	    settings.labelsSettings = combineLabelsSettings(props.labelsSettings, settings.labelsSettings);
 55	    this.state = { ...settings, isOpen: false, allSelected: false };
 56	  }
 57	
 58	  checkSelected = (): void => {
 59	    let allSelected = true;
 60	
 61	    this.state.labelsSettings.forEach(lblSetting => {
 62	      if (lblSetting.checked === false) {
 63	        allSelected = false;
 64	      } else {
 65	        Object.keys(lblSetting.values).forEach(value => {
 66	          if (lblSetting.values[value] === false) {
 67	            allSelected = false;
 68	          }
 69	        });
 70	      }
 71	    });
 72	
 73	    this.setState({ allSelected: allSelected });
 74	  };
 75	
 76	  componentDidUpdate(prevProps: Props): void {
 77	    // TODO Move the sync of URL and state to a global place
 78	    const changeDirection = prevProps.direction !== this.props.direction;
 79	    const settings = retrieveMetricsSettings();
 80	    let initLabelSettings = changeDirection ? settings.labelsSettings : new Map();
 81	    const stateLabelsSettings = changeDirection ? initLabelSettings : this.state.labelsSettings;
 82	    const labelsSettings = combineLabelsSettings(this.props.labelsSettings, stateLabelsSettings);
 83	
 84	    if (!isEqual(stateLabelsSettings, labelsSettings) || changeDirection) {
 85	      this.setState(prevState => {
 86	        return {
 87	          labelsSettings: labelsSettings,
 88	          showQuantiles: changeDirection ? settings.showQuantiles : prevState.showQuantiles,
 89	          showAverage: changeDirection ? settings.showAverage : prevState.showAverage,
 90	          showSpans: changeDirection ? settings.showSpans : prevState.showSpans
 91	        };
 92	      }, this.checkSelected);
 93	    }
 94	  }
 95	
 96	  private onToggle = (isOpen: boolean): void => {
 97	    this.setState({ isOpen: isOpen });
 98	  };
 99	
100	  onGroupingChanged = (label: PromLabel, checked: boolean): void => {
101	    const objLbl = this.state.labelsSettings.get(label);
102	
103	    if (objLbl) {
104	      objLbl.checked = checked;
105	    }
106	
107	    this.updateLabelsSettingsURL(this.state.labelsSettings);
108	
109	    this.setState(
110	      {
111	        labelsSettings: new Map(this.state.labelsSettings)
112	      },
113	      () => {
114	        this.props.onChanged(this.state);
115	        this.checkSelected();
116	      }
117	    );
118	  };
119	
120	  onLabelsFiltersChanged = (label: PromLabel, value: string, checked: boolean, singleSelection: boolean): void => {
121	    const newValues = mergeLabelFilter(this.state.labelsSettings, label, value, checked, singleSelection);
122	    this.updateLabelsSettingsURL(newValues);
123	
124	    this.setState({ labelsSettings: newValues }, () => {
125	      this.props.onLabelsFiltersChanged(newValues);
126	      this.checkSelected();
127	    });
128	  };
129	
130	  updateLabelsSettingsURL = (labelsSettings: LabelsSettings): void => {
131	    // E.g.: bylbl=version=v1,v2,v4
132	    const urlParams = new URLSearchParams(location.getSearch());
133	    urlParams.delete(URLParam.BY_LABELS);
134	
135	    labelsSettings.forEach((lbl, name) => {
136	      if (lbl.checked) {
137	        const filters = Object.keys(lbl.values)
138	          .filter(k => lbl.values[k])
139	          .join(',');
140	
141	        if (filters) {
142	          urlParams.append(URLParam.BY_LABELS, `${name}=${filters}`);
143	        } else {
144	          urlParams.append(URLParam.BY_LABELS, name);
145	        }
146	      }
147	    });
148	
149	    router.navigate(`${location.getPathname()}?${urlParams.toString()}`, { replace: true });
150	  };
151	
152	  onHistogramAverageChanged = (checked: boolean): void => {
153	    const urlParams = new URLSearchParams(location.getSearch());
154	    urlParams.set(URLParam.SHOW_AVERAGE, String(checked));
155	    router.navigate(`${location.getPathname()}?${urlParams.toString()}`, { replace: true });
156	
157	    this.setState({ showAverage: checked }, () => this.props.onChanged(this.state));
158	  };
159	
160	  onHistogramOptionsChanged = (quantile: Quantiles, checked: boolean): void => {
161	    const newQuantiles = checked
162	      ? [quantile].concat(this.state.showQuantiles)
163	      : this.state.showQuantiles.filter(q => quantile !== q);
164	
165	    const urlParams = new URLSearchParams(location.getSearch());
166	    urlParams.set(URLParam.QUANTILES, newQuantiles.join(' '));
167	    router.navigate(`${location.getPathname()}?${urlParams.toString()}`, { replace: true });
168	
169	    this.setState({ showQuantiles: newQuantiles }, () => this.props.onChanged(this.state));
170	  };
171	
172	  bulkUpdate = (selected: boolean): void => {
173	    this.state.labelsSettings.forEach(lblSetting => {
174	      lblSetting.checked = selected;
175	
176	      Object.keys(lblSetting.values).forEach(value => {
177	        lblSetting.values[value] = selected;
178	      });
179	    });
180	
181	    this.updateLabelsSettingsURL(this.state.labelsSettings);
182	
183	    this.setState(
184	      {
185	        labelsSettings: new Map(this.state.labelsSettings)
186	      },
187	      () => {
188	        this.props.onChanged(this.state);
189	      }
190	    );
191	  };
192	
193	  onBulkAll = (): void => {
194	    this.bulkUpdate(true);
195	    this.setState({ allSelected: true });
196	  };
197	
198	  onBulkNone = (): void => {
199	    this.bulkUpdate(false);
200	    this.setState({ allSelected: false });
201	  };
202	
203	  render(): React.ReactNode {
204	    const hasHistograms = this.props.hasHistograms;
205	    const hasLabels = this.state.labelsSettings.size > 0;
206	
207	    if (!hasHistograms && !hasLabels) {
208	      return null;
209	    }
210	
211	    return (
212	      <Dropdown
213	        toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
214	          <MenuToggle ref={toggleRef} onClick={() => this.onToggle(!this.state.isOpen)} isExpanded={this.state.isOpen}>
215	            Metrics Settings
216	          </MenuToggle>
217	        )}
218	        isOpen={this.state.isOpen}
219	        onOpenChange={(isOpen: boolean) => this.onToggle(isOpen)}
220	      >
221	        <DropdownList>
222	          {hasLabels && this.renderBulkSelector()}
223	          {hasLabels && this.renderLabelOptions()}
224	          {hasHistograms && this.renderHistogramOptions()}
225	        </DropdownList>
226	      </Dropdown>
227	    );
228	  }
229	
230	  renderBulkSelector(): React.ReactNode {
231	    return (
232	      <div>
233	        <div className={itemStyleWithoutInfo}>
234	          <Checkbox
235	            id="bulk-select-id"
236	            key="bulk-select-key"
237	            aria-label="Select all metric/label filters"
238	            isChecked={this.state.allSelected}
239	            onChange={() => {
240	              if (this.state.allSelected) {
241	                this.onBulkNone();
242	              } else {
243	                this.onBulkAll();
244	              }
245	            }}
246	          />
247	          <span className={checkboxSelectAllStyle}>Select all metric/label filters</span>
248	        </div>
249	        <Divider />
250	      </div>
251	    );
252	  }
253	
254	  renderLabelOptions(): React.ReactNode {
255	    const displayGroupingLabels: any[] = [];
256	
257	    this.state.labelsSettings.forEach((lblObj, promName) => {
258	      const labelsHTML =
259	        lblObj.checked && lblObj.values
260	          ? Object.keys(lblObj.values).map(val => (
261	              <div key={`groupings_${promName}_${val}`} className={secondLevelStyle}>
262	                {lblObj.singleSelection ? (
263	                  <Radio
264	                    isChecked={lblObj.values[val]}
265	                    id={val}
266	                    className={checkboxStyle}
267	                    onChange={(_event, _) => this.onLabelsFiltersChanged(promName, val, true, true)}
268	                    label={prettyLabelValues(promName, val)}
269	                    name={val}
270	                    value={val}
271	                  />
272	                ) : (
273	                  <label>
274	                    <Checkbox
275	                      id={val}
276	                      className={checkboxStyle}
277	                      isChecked={lblObj.values[val]}
278	                      onChange={(_event, checked) => this.onLabelsFiltersChanged(promName, val, checked, false)}
279	                      label={prettyLabelValues(promName, val)}
280	                    />
281	                  </label>
282	                )}
283	              </div>
284	            ))
285	          : null;
286	
287	      displayGroupingLabels.push(
288	        <div key={`groupings_${promName}`}>
289	          <label>
290	            <Checkbox
291	              id={lblObj.displayName}
292	              className={checkboxStyle}
293	              label={lblObj.displayName}
294	              isChecked={lblObj.checked}
295	              onChange={(_event, checked) => this.onGroupingChanged(promName, checked)}
296	            />
297	          </label>
298	          {labelsHTML}
299	        </div>
300	      );
301	    });
302	
303	    return (
304	      <>
305	        <label className={classes(titleLabelStyle, titleStyle, labelStyle)}>Show metrics by:</label>
306	        {displayGroupingLabels}
307	        <div className={spacerStyle} />
308	      </>
309	    );
310	  }
311	
312	  renderHistogramOptions(): React.ReactNode {
313	    const displayHistogramOptions = [
314	      <div key="histo_avg">
315	        <label>
316	          <Checkbox
317	            id="histo_avg"
318	            className={checkboxStyle}
319	            isChecked={this.state.showAverage && this.props.hasHistogramsAverage}
320	            isDisabled={!this.props.hasHistogramsAverage}
321	            onChange={(_event, checked) => this.onHistogramAverageChanged(checked)}
322	            label="Average"
323	          />
324	        </label>
325	      </div>
326	    ].concat(
327	      allQuantiles.map((o, idx) => {
328	        const checked = this.state.showQuantiles.includes(o);
329	        return (
330	          <div key={`histo_${idx}`}>
331	            <label>
332	              <Checkbox
333	                id={o}
334	                className={checkboxStyle}
335	                isChecked={checked && this.props.hasHistogramsPercentiles}
336	                isDisabled={!this.props.hasHistogramsPercentiles}
337	                onChange={(_event, checked) => this.onHistogramOptionsChanged(o, checked)}
338	                label={`Quantile ${o}`}
339	              />
340	            </label>
341	          </div>
342	        );
343	      })
344	    );
345	
346	    return (
347	      <>
348	        <label className={classes(titleLabelStyle, titleStyle, labelStyle)} style={{ paddingRight: '0.5rem' }}>
349	          Histograms:
350	        </label>
351	
352	        <Tooltip
353	          key="tooltip_histograms"
354	          position={TooltipPosition.right}
355	          content={
356	            <div style={{ textAlign: 'left' }}>
357	              <div>
358	                "No data available" is displayed for a histogram that does not have telemetry supporting the selected
359	                option. If no histograms support the necessary telemetry, the option will be disabled.
360	              </div>
361	            </div>
362	          }
363	        >
364	          <KialiIcon.Info />
365	        </Tooltip>
366	
367	        {displayHistogramOptions}
368	        <div className={spacerStyle} />
369	      </>
370	    );
371	  }
372	}

