219	        onOpenChange={(isOpen: boolean) => this.onToggle(isOpen)}
220	        popperProps={{ appendTo: 'inline' }}
221	      >
222	        <DropdownList>
223	          {hasLabels && this.renderBulkSelector()}
224	          {hasLabels && this.renderLabelOptions()}
225	          {hasHistograms && this.renderHistogramOptions()}
226	        </DropdownList>
227	      </Dropdown>
228	    );
229	  }
