255	  renderLabelOptions(): React.ReactNode {
256	    const displayGroupingLabels: any[] = [];
257	
258	    this.state.labelsSettings.forEach((lblObj, promName) => {
259	      const labelsHTML =
260	        lblObj.checked && lblObj.values
261	          ? Object.keys(lblObj.values).map(val => (
262	              <div key={`groupings_${promName}_${val}`} className={secondLevelStyle}>
263	                {lblObj.singleSelection ? (
264	                  <Radio
265	                    isChecked={lblObj.values[val]}
266	                    id={val}
267	                    className={checkboxStyle}
268	                    onChange={(_event, _) => this.onLabelsFiltersChanged(promName, val, true, true)}
269	                    label={prettyLabelValues(promName, val)}
270	                    name={val}
271	                    value={val}
272	                  />
273	                ) : (
274	                  <label>
275	                    <Checkbox
276	                      id={val}
277	                      className={checkboxStyle}
278	                      isChecked={lblObj.values[val]}
279	                      onChange={(_event, checked) => this.onLabelsFiltersChanged(promName, val, checked, false)}
280	                      label={prettyLabelValues(promName, val)}
281	                    />
282	                  </label>
283	                )}
284	              </div>
285	            ))
286	          : null;
287	
288	      displayGroupingLabels.push(
289	        <div key={`groupings_${promName}`}>
290	          <label>
291	            <Checkbox
292	              id={lblObj.displayName}
293	              className={checkboxStyle}
294	              label={lblObj.displayName}
295	              isChecked={lblObj.checked}
296	              onChange={(_event, checked) => this.onGroupingChanged(promName, checked)}
297	            />
298	          </label>
299	          {labelsHTML}
300	        </div>
301	      );
302	    });
303	
304	    return (
305	      <>
306	        <label className={classes(titleLabelStyle, titleStyle, labelStyle)}>Show metrics by:</label>
307	        {displayGroupingLabels}
308	        <div className={spacerStyle} />
309	      </>
310	    );
311	  }
