314	    const displayHistogramOptions = [
315	      <div key="histo_avg">
316	        <label>
317	          <Checkbox
318	            id="histo_avg"
319	            className={checkboxStyle}
320	            isChecked={this.state.showAverage && this.props.hasHistogramsAverage}
