332	            <label>
333	              <Checkbox
334	                id={o}
335	                className={checkboxStyle}
336	                isChecked={checked && this.props.hasHistogramsPercentiles}
337	                isDisabled={!this.props.hasHistogramsPercentiles}
338	                onChange={(_event, checked) => this.onHistogramOptionsChanged(o, checked)}
339	                label={`Quantile ${o}`}
